using System.ComponentModel;
using System.Reflection;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(sp =>
    new OpenAIChatClient(new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId)));

builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var tools = host.Services.GetRequiredService<ResearchTools>();

// Create AIFunction tools from the ResearchTools methods
var toolMethods = typeof(ResearchTools).GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.GetCustomAttribute<DescriptionAttribute>() is not null)
    .Select(m => AIFunctionFactory.Create(m, tools))
    .ToList<AITool>();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "An AI agent that researches topics by searching the web and taking notes",
    """
    You are a research agent. Your goal is to research a topic thoroughly by:
    1. Searching the web for relevant information using the SearchWeb tool
    2. Taking notes on key findings using the TakeNote tool
    3. Performing multiple searches to cover different aspects of the topic
    4. Summarizing all your notes into a final comprehensive summary

    Always take notes on important findings before moving to the next search.
    When you have gathered enough information, retrieve all notes and produce a final summary.
    """,
    toolMethods);

var topic = args.Length > 0 ? string.Join(' ', args) : "recent advances in quantum computing 2025";

Console.WriteLine($"🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n📝 Research Notes:");
Console.WriteLine(new string('-', 40));
foreach (var note in tools.GetNotes())
{
    Console.WriteLine($"• {note}");
}

/// <summary>Tools available to the research agent.</summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a query. Returns search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var request = new HttpRequestMessage(HttpMethod.Get,
                $"https://html.duckduckgo.com/html/?q={encoded}");
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await _httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();
            var snippets = ExtractSnippets(html);

            return snippets.Length > 0
                ? $"Search results for '{query}':\n{snippets}"
                : $"No results found for '{query}'. Try a different search term.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }

    [Description("Save a research note. Use this to record important findings from search results.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📌 Note saved ({_notes.Count} total)");
        return $"Note saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes to review before summarizing.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

